// Track: Portuguese (Portugal), for an English speaker. Deepened 2026-07-10
// (#38 pass, parity standard): all six CEFR tiers ≥3, promptNative subtitles,
// first C1/C2 content — future subjunctive tu-forms, the personal infinitive,
// MESOCLISIS (dar-te-ei), vós recognition, desenrascar-se/desassossego/fado,
// and the propina/rapariga/constipado cross-Atlantic traps. Same pão
// duplicate-option bug as ptBr found and fixed here too.
// ⚠️ PENDING #41: needs a reviewer from Portugal specifically (regional rule).
// Deliberately NOT a reskin of ptBrForEn.js — vocabulary for everyday things differs almost
// entirely (autocarro/comboio/telemóvel vs. Brazil's ônibus/trem/celular),
// the infinitive construction ("estar a + infinitive") replaces Brazil's
// gerund preference, "tu" replaces "você" as the default informal address,
// and the phonetics are strikingly different — European Portuguese reduces
// unstressed vowels heavily and turns syllable-final 's' into a "sh" sound.

import { buildFrequencyBank } from "../../lib/frequencyVocab";
import WORDS from "../vocab/ptPtWords";

const cap = (s) => s.charAt(0).toUpperCase() + s.slice(1);

// Word Bank prompt formulas for buildFrequencyBank (generator is language-neutral).
const PT_FORMULAS = {
  recognitionPrompt: (w) => `'${cap(w)}' significa...`,
  recognitionNative: (w) => ({ en: `'${cap(w)}' means...` }),
  recognitionExplain: (w, g, noteEn) => ({
    en: `'${cap(w)}' means ${g}.${noteEn}`,
    es: `'${cap(w)}' significa ${g}.`,
  }),
  productionPrompt: (g) => `Como se diz '${g}' em português?`,
  productionNative: (g) => ({ en: `How do you say '${g}' in Portuguese?` }),
  productionExplain: (w, g, noteEn) => ({
    en: `'${g}' is '${w}'.${noteEn}`,
    es: `'${g}' se dice '${w}'.`,
  }),
};

import { THEMES, tagFor } from "./ptPtForEnTags";

